external_knowledge:
- 'main branch' is often referred to as 'master' in software development;
- '64-bit architecture' corresponds to the 'x86-64' architecture name;
- 'build rates' refer to the total number of builds;
- 'success' and 'failure' rates are represented by the number of successful and failed builds respectively.

sql:
SELECT SUM(total_builds) 
FROM build_metrics 
WHERE branch = 'main';

SELECT build_id
FROM build_metrics
WHERE success_count > 5;

SELECT arch, SUM(fail_count) AS Total_Failed_Builds
FROM build_metrics
GROUP BY arch;

SELECT build_id
FROM build_details
WHERE status = 'failed';

SELECT u.user_name, bf.error_message, bf.failure_reason, bf.resolution
FROM build_failures bf
INNER JOIN users u ON bf.resolved_by = u.user_id;

